Rules.InvariantScript:
Set(timersRun,true);


ClearCollect(
    colProductionOperations,
    Filter(
        'Production Operations',
        OrderType = "EN" 
    )
);
Set(
    signIN,
    false
);
Set(
    varADPIn,
    Blank()
);
ClearCollect(
    colUsers,
    RenameColumns(
        ShowColumns(
            Filter(
                Employees,
                Status = "Active" && Branches = "Ennis" && Machinist = true
            ),
            ADPEmpNumber,
            'First Name',
            'Last Name',
            'Full Name',
            Branches
        ),
        field_0,
        EmpID,
        field_2,
        'First Name',
        field_4,
        'Last Name',
        Title,
        'Full Name',
        field_22,
        Branch
    )
);
ClearCollect(
    varDetails,
    ShowColumns(
        Filter(
            AddColumns(
                'Details Type',
                BranchValue,
                Branch.Value
            ),
            BranchValue = "Ennis"
        ),
        ID,
        OptionStep,
        Title,
        TypeII,
        BranchValue
    )
);
ClearCollect(
    _RadioChoices,
    _Shifts,
    RenameColumns(
        varDetails,
        BranchValue,
        Branch
    )
);
ClearCollect(
    colStations,
    Stations
);
Set(
    varUsersLocation,
    "Ennis"
);

Set(
    _off365Acct,
    Office365Users.UserProfileV2(User().EntraObjectId).jobTitle
);
If(
    IsBlank(_off365Acct),
    Set(
        varMachineNo,
        LookUp(
            colStations,
            EmailTest = User().Email,
            'Machine No'
        )
    ),
    Set(
        varMachineNo,
        _off365Acct
    )
);
ClearCollect(
    colPOrders,
    Filter(
        'Production Order Acu Export',
        ('Order Type' = "EN" || 'Order Type' = "RD") && (Status = "In Process" || Status = "Released" || Status = "Planned")
    )
);
ClearCollect(
    colEnnisStartStop,
    'Ennis Start and Stop Time Inputs'
);
ClearCollect(
    colEnnisTimeEntry,
    FirstN(
        Sort(
            'Ennis Machinist Time Entry',
            LaborDate,
            SortOrder.Descending
        ),
        300
    )
);
ClearCollect(
    colENTimeCombined,
    AddColumns(
        colEnnisStartStop,
        Source,
        "Input"
    ),
    AddColumns(
        colEnnisTimeEntry,
        Source,
        "Final"
    )
);
ClearCollect(
    colFilEmpStartStop,
    Filter(
        colENTimeCombined,
        Value(EmpID) = Value(varCurrentBadge)
    )
);
ClearCollect(
    colSOP,
    'Standard Operating Procedures'
);
Set(timersRun,false);

Set(varStartDate, DateAdd(Today(), -1, TimeUnit.Days));
Set(varEndDate, DateAdd(Today(), 1, TimeUnit.Days));
Set(varLastDate,DateAdd(Today(), -1, TimeUnit.Days));

