    CombinedData,
    [
        "Shop Time",
        "Set Up Time"
    ],
    Distinct(
        Filter(
            'Production Operations_1',
            Status = "In Process" && StartsWith(
                ProductionNumber,
                "ewo"
            )
        ),
        ProductionNumber
    )
);*/

_AppName = "Ennis CNC Time Entry";
_AppID = "8250839b-f712-465e-877f-9bad5b828fcf";
_AppVerison ="764";
varMainFill=RGBA(27,28,48,1);
varMainFill2=RGBA(49,49,87,0.50);
varMainFill3=RGBA(53,60,71,1);
_Hours=["00","01","02","03","04","05","06","07","08","09","10","11","12","13","14","15","16"];
_Minutes=["00","05","10","15","20","25","30","35","40","45","50","55"];
_Shifts = [{Branch:"Ennis",ID:40,OptionStep:1,Title:"Day Shift"},{ Branch:"Ennis",ID:41,OptionStep:1,Title:"Night Shift"}];
_HeaderButtons = [{Title: "Exit",icon:Icon.Leave},{Title:"Time Input",icon:Icon.Database},{Title:"Misc Time",icon:Icon.Clock},{Title:"Manual Time",icon:Icon.Clock},{Title:"Clean",icon:Icon.ClearDrawing},{Title:"Refresh",icon:Icon.Sync},{Title:"Settings",icon:Icon.Settings}];
